Verilating the following SystemVerilog code
```SystemVerilog
module top;

logic tb_clk, tb_rstn;

initial begin
    tb_clk = 1'b0;
    tb_rstn = 1'b0;
    #5 tb_rstn = 1'b1;
end

always #1 tb_clk = ~tb_clk;

endmodule
```
and main.cpp (adapted from the generated one with --main)
```C++
// Verilated -*- C++ -*-
// DESCRIPTION: main() calling loop, created with Verilator --main

#include "verilated.h"
#include "Vtop.h"

//======================
Vtop *topp;
uint64_t main_time;
VerilatedContext *contextp;

void save_model(const char* filename) {
    VerilatedSave os;
    os.open(filename);
    main_time = contextp->time();
    os << main_time;  // user code must save the timestamp
    os << *topp;
}

void restore_model(const char* filename) {
    VerilatedRestore os;
    os.open(filename);
    os >> main_time;
    os >> *topp;
    contextp->time(main_time);
}

int main(int argc, char** argv, char**) {
    // Setup context, defaults, and parse command line
    Verilated::debug(0);
    contextp->commandArgs(argc, argv);

    // Simulate until $finish
    while (!contextp->gotFinish()) {
        // Evaluate model
        topp->eval();
        // Advance time
        if (!topp->eventsPending()) break;
        contextp->time(topp->nextTimeSlot());
    }

    if (!contextp->gotFinish()) {
        VL_DEBUG_IF(VL_PRINTF("+ Exiting without $finish; no events left\n"););
    }

    // Execute 'final' processes
    topp->final();

    // Print statistical summary report
    contextp->statsPrintSummary();
    
    delete topp;
    delete contextp;
    
    return 0;
}
```
gives this error:
```
In file included from Vtop__ALL.cpp:6:
Vtop___024root__Slow.cpp: In member function ‘void Vtop___024root::__Vserialize(VerilatedSerialize&)’:
Vtop___024root__Slow.cpp:35:7: error: no match for ‘operator<<’ (operand types are ‘VerilatedSerialize’ and ‘VlDelayScheduler’)
   35 |     os<<__VdlySched;
      |     ~~^~~~~~~~~~~~~
      |     |   |
      |     |   VlDelayScheduler
      |     VerilatedSerialize
```
I have not seen any mention of the --savable and --timing flags being incompatible, but maybe I missed it (apologies if that is the case).

What 'verilator' command line do we use to run your example?
`verilator --cc --exe --timing --build --savable top.sv Vtop_main.cpp`
What 'verilator --version' are you using?  Did you try it with the git master version?
`Verilator 5.031 devel rev v5.030-155-gc093b2434` master version at the time of writing
What OS and distribution are you using?
`Ubuntu 22.04`
